-- PetanQ - Waalse clubs met officieel adres en e-mailadres, aangeleverd door
-- Frederic via de FBFP-bron "SIGNALETIQUES CLUBS" (2026-07-08).
-- Provincie afgeleid uit de postcode (Brussel <1300, Waals-Brabant >=1300 voor
-- de gecombineerde BWBC-federatiecode); regio wordt automatisch afgeleid door
-- de bestaande trigger.

on conflict (lower(naam), lower(gemeente)) do update set
  adres = excluded.adres,
  contact_email = coalesce(excluded.contact_email, clubs.contact_email);
